  #grid-container { overflow: auto; min-width: 600px; min-height: 400px; }
  table { border-collapse: collapse; background: white; }
  th, td { border: 1px solid #999; padding: 0; text-align: center; }
  th { background: #ddd; min-width: 50px; width: 60px; height: 28px; font-weight: bold; }
  td { width: 60px; min-width: 60px; height: 28px; }
  td input {
    width: 100%; height: 100%; border: none; outline: none;
    text-align: right; font-family: monospace; font-size: 14px;
    padding: 2px 4px; background: transparent;
  }
  td input:focus { background: #e8f0fe; }
  td.error { background: #ffe0e0; }
  td.cycle { background: #fff0e0; }
  #controls { margin-top: 10px; }
  #export { padding: 8px 16px; font-size: 14px; cursor: pointer; }
  #csv { width: 100%; height: 100px; margin-top: 10px; font-family: monospace; font-size: 12px; }
</style>
</head>
<body>
<h1>Mini Spreadsheet</h1>
<div id="grid-container"></div>
<div id="controls">
  <button id="export">Export CSV</button>
  <textarea id="csv" readonly></textarea>
</div>
<script>
(function() {
  const COLS = 10;
  const ROWS = 10;
  const colLetters = 'ABCDEFGHIJ';

  const rawValues = {};
  const computedValues = {};
  const dependencies = {};
  const dependents = {};
  const errorCells = new Set();
  const cycleCells = new Set();

  for (let r = 1; r <= ROWS; r++) {
    for (let c = 0; c < COLS; c++) {
      const id = colLetters[c] + r;
      rawValues[id] = '';
      computedValues[id] = '';
      dependencies[id] = new Set();
      dependents[id] = new Set();
    }
  }

  const container = document.getElementById('grid-container');
  const table = document.createElement('table');

  const thead = document.createElement('thead');
  const headerRow = document.createElement('tr');
  const corner = document.createElement('th');
  headerRow.appendChild(corner);
  for (let c = 0; c < COLS; c++) {
    const th = document.createElement('th');
    th.textContent = colLetters[c];
    headerRow.appendChild(th);
  }
  thead.appendChild(headerRow);
  table.appendChild(thead);

  const tbody = document.createElement('tbody');
  for (let r = 1; r <= ROWS; r++) {
    const tr = document.createElement('tr');
    const rowHeader = document.createElement('th');
    rowHeader.textContent = r;
    tr.appendChild(rowHeader);
    for (let c = 0; c < COLS; c++) {
      const id = colLetters[c] + r;
      const td = document.createElement('td');
      td.id = 'td-' + id;
      const input = document.createElement('input');
      input.type = 'text';
      input.id = 'cell-' + id;
      input.dataset.cellId = id;

      input.addEventListener('focus', function() {
        this.value = rawValues[id];
        this.classList.remove('error', 'cycle');
      });

      input.addEventListener('blur', function() {
        commitCell(id);
      });

      input.addEventListener('keydown', function(e) {
        if (e.key === 'Enter') {
          e.preventDefault();
          commitCell(id);
        }
      });

      td.appendChild(input);
      tr.appendChild(td);
    }
    tbody.appendChild(tr);
  }
  table.appendChild(tbody);
  container.appendChild(table);

  function isValidCell(ref) {
    if (ref.length < 2) return false;
    const col = ref.substring(0, ref.length - 1);
    const row = ref.substring(ref.length - 1);
    if (col.length !== 1) return false;
    if (col[0] < 'A' || col[0] > 'J') return false;
    const rowNum = parseInt(row, 10);
    if (isNaN(rowNum) || rowNum < 1 || rowNum > ROWS) return false;
    return true;
  }

  function extractCellRefs(formula) {
    const refs = new Set();
    const regex = /[A-Ja-j][0-9]+/g;
    let match;
    while ((match = regex.exec(formula)) !== null) {
      const ref = match[0].toUpperCase();
      if (isValidCell(ref)) {
        refs.add(ref);
      }
    }
    return refs;
  }

  function commitCell(cellId) {
    const input = document.getElementById('cell-' + cellId);
    const newVal = input.value;
    rawValues[cellId] = newVal;

    errorCells.delete(cellId);
    cycleCells.delete(cellId);

    dependencies[cellId] = new Set();
    if (newVal.startsWith('=')) {
      const deps = extractCellRefs(newVal.substring(1));
      deps.forEach(function(d) {
        dependencies[cellId].add(d);
        dependents[d].add(cellId);
      });
    }

    recalculate(cellId);
    updateDisplay(cellId);
  }

  function recalculate(cellId) {
    const toRecalc = new Set();
    toRecalc.add(cellId);

    const queue = [cellId];
    while (queue.length > 0) {
      const current = queue.shift();
      dependents[current].forEach(function(dep) {
        if (!toRecalc.has(dep)) {
          toRecalc.add(dep);
          queue.push(dep);
        }
      });
    }

    const order = topologicalSort(toRecalc);
    if (order === null) {
      toRecalc.forEach(function(id) {
        cycleCells.add(id);
        computedValues[id] = '#CYCLE';
        updateDisplay(id);
      });
      return;
    }

    order.forEach(function(id) {
      cycleCells.delete(id);
      const result = evaluateFormula(rawValues[id], id);
      if (result.error) {
        errorCells.add(id);
        computedValues[id] = '#ERR';
      } else {
        errorCells.delete(id);
        computedValues[id] = result.value;
      }
      updateDisplay(id);
    });
  }

  function topologicalSort(cellIds) {
    const visited = new Set();
    const tempMark = new Set();
    const order = [];

    function visit(cellId) {
      if (tempMark.has(cellId)) return null;
      if (visited.has(cellId)) return true;

      tempMark.add(cellId);
      dependencies[cellId].forEach(function(dep) {
        if (cellIds.has(dep)) {
          const result = visit(dep);
          if (result === null) return null;
        }
      });

      tempMark.delete(cellId);
      visited.add(cellId);
      order.push(cellId);
      return true;
    }

    cellIds.forEach(function(cellId) {
      const result = visit(cellId);
      if (result === null) return null;
    });

    return order;
  }

  function evaluateFormula(formula, cellId) {
    if (!formula.startsWith('=')) {
      const val = parseFloat(formula);
      if (isNaN(val)) return { value: formula };
      return { value: String(val) };
    }

    const expr = formula.substring(1);
    if (expr.trim() === '') return { error: true };

    const tokens = tokenize(expr);
    if (!tokens) return { error: true };

    const parser = new FormulaParser(tokens, cellId);
    const result = parser.parse();

    if (result.error) return { error: true };
    if (result.value === null || result.value === undefined) return { error: true };

    const num = parseFloat(result.value);
    if (isNaN(num)) return { error: true };

    return { value: String(num) };
  }

  function tokenize(formula) {
    const tokens = [];
    let i = 0;
    while (i < formula.length) {
      if (formula[i] === ' ') { i++; continue; }
      if ((formula[i] >= '0' && formula[i] <= '9') || formula[i] === '.') {
        let num = '';
        while (i < formula.length && ((formula[i] >= '0' && formula[i] <= '9') || formula[i] === '.')) {
          num += formula[i]; i++;
        }
        tokens.push({ type: 'NUMBER', value: parseFloat(num) });
      } else if ((formula[i] >= 'A' && formula[i] <= 'Z') || (formula[i] >= 'a' && formula[i] <= 'z')) {
        let ref = '';
        while (i < formula.length && ((formula[i] >= 'A' && formula[i] <= 'Z') || (formula[i] >= 'a' && formula[i] <= 'z') || (formula[i] >= '0' && formula[i] <= '9'))) {
          ref += formula[i]; i++;
        }
        tokens.push({ type: 'CELL_REF', value: ref.toUpperCase() });
      } else if (formula[i] === '+') { tokens.push({ type: 'PLUS' }); i++; }
      else if (formula[i] === '-') { tokens.push({ type: 'MINUS' }); i++; }
      else if (formula[i] === '*') { tokens.push({ type: 'STAR' }); i++; }
      else if (formula[i] === '/') { tokens.push({ type: 'SLASH' }); i++; }
      else if (formula[i] === '(') { tokens.push({ type: 'LPAREN' }); i++; }
      else if (formula[i] === ')') { tokens.push({ type: 'RPAREN' }); i++; }
      else { return null; }
    }
    tokens.push({ type: 'EOF' });
    return tokens;
  }

  function FormulaParser(tokens, cellId) {
    this.tokens = tokens;
    this.pos = 0;
    this.cellId = cellId;
  }

  FormulaParser.prototype.parse = function() {
    const result = this.expression();
    if (this.current().type !== 'EOF') return { error: true };
    return result;
  };

  FormulaParser.prototype.current = function() {
    return this.tokens[this.pos] || { type: 'EOF' };
  };

  FormulaParser.prototype.consume = function(type) {
    if (this.current().type === type) {
      const token = this.tokens[this.pos];
      this.pos++;
      return token;
    }
    return null;
  };

  FormulaParser.prototype.expression = function() {
    let left = this.term();
    if (left.error) return left;

    while (this.current().type === 'PLUS' || this.current().type === 'MINUS') {
      const op = this.current().type;
      this.pos++;
      const right = this.term();
      if (right.error) return right;

      if (op === 'PLUS') left = { value: left.value + right.value };
      else left = { value: left.value - right.value };
    }
    return left;
  };

  FormulaParser.prototype.term = function() {
    let left = this.factor();
    if (left.error) return left;

    while (this.current().type === 'STAR' || this.current().type === 'SLASH') {
      const op = this.current().type;
      this.pos++;
      const right = this.factor();
      if (right.error) return right;

      if (op === 'STAR') left = { value: left.value * right.value };
      else {
        if (right.value === 0) return { error: true };
        left = { value: left.value / right.value };
      }
    }
    return left;
  };

  FormulaParser.prototype.factor = function() {
    if (this.current().type === 'MINUS') {
      this.pos++;
      const val = this.factor();
      if (val.error) return val;
      return { value: -val.value };
    }
    if (this.current().type === 'PLUS') {
      this.pos++;
      const val = this.factor();
      if (val.error) return val;
      return { value: val.value };
    }

    if (this.current().type === 'LPAREN') {
      this.pos++;
      const val = this.expression();
      if (val.error) return val;
      if (!this.consume('RPAREN')) return { error: true };
      return val;
    }

    if (this.current().type === 'NUMBER') {
      const token = this.tokens[this.pos];
      this.pos++;
      return { value: token.value };
    }

